function resolveFirstName(input, nes) {
  const candidates = [
    nes && nes.lead_first_name,
    nes && nes.first_name,
    input && input.first_name,
    input && input.First_name,
    input && input.raw_payload && input.raw_payload.First_name,
    input && input.raw_payload && input.raw_payload.first_name
  ];

  for (const candidate of candidates) {
    const raw = String(candidate == null ? '' : candidate).trim();
    if (!raw) continue;
    const lower = raw.toLowerCase();
    const rejected = ['unknown', 'n/a', 'na', 'test', 'admin', 'friend', 'there'];
    if (rejected.includes(lower)) continue;
    if (/^\d+$/.test(raw)) continue;
    if (/[@<>{}\r\n\t]/.test(raw)) continue;
    if (/https?:\/\//i.test(raw)) continue;
    return raw;
  }

  return null;
}

function resolveEaccount(input, nes) {
  const candidates = [
    nes && nes.eaccount,
    nes && nes.email_account,
    nes && nes.sender_email,
    input && input.eaccount,
    input && input.email_account,
    input && input.raw_payload && input.raw_payload.email_account
  ];

  for (const candidate of candidates) {
    const raw = String(candidate == null ? '' : candidate).trim().toLowerCase();
    if (raw.includes('@')) return raw;
  }

  return '';
}

function senderNameFromEaccount(eaccount) {
  const config = SENDER_CONFIG[eaccount] || null;
  if (config && config.senderName) return config.senderName;

  const prefix = String(eaccount || '').split('@')[0].toLowerCase();
  if (prefix === 'hamzah') return 'Hamza';
  if (prefix === 'zahid') return 'Zahid';

  return null;
}

function bookingLinkFromEaccount(eaccount) {
  const config = SENDER_CONFIG[eaccount] || null;
  return config && config.bookingLink ? config.bookingLink : null;
}

return items.map(item => {
  const input = item.json || {};
  const decision = input.decision || {};
  const nes = input.nes || {};

  const templateId = decision.reply_template_id || null;
  const template = templateId ? TEMPLATE_REGISTRY[templateId] : null;

  let draft;

  if (!template) {
    draft = {
      template_id: templateId,
      draft_text: null,
      draft_status: decision.reply_draft_status || 'NOT_APPLICABLE',
      missing_variables: [],
      human_review_required: decision.human_review_required === true,
      notes: 'No fixed reply template applies to this category; any reply is human-authored.'
    };
  } else {
    const firstName = resolveFirstName(input, nes);
    const eaccountKey = resolveEaccount(input, nes);
    const senderName = senderNameFromEaccount(eaccountKey);
    const bookingLink = bookingLinkFromEaccount(eaccountKey);

    const missingVariables = [];
    if (!firstName) missingVariables.push('firstName');
    if (!senderName) missingVariables.push('senderName');

    let lines = [...template.paragraphs];

    if (!firstName) {
      const variant = NO_NAME_VARIANTS[templateId];
      if (variant) {
        lines = lines.map(line => (line === variant.from ? variant.to : line));
      }
    }

    if (template.bookingLinkLine && !bookingLink) {
      lines = lines.filter(line => line !== template.bookingLinkLine);
      missingVariables.push('bookingLink');
    }

    const substitutions = {
      firstName: firstName || 'there',
      senderName: senderName || '[[senderName: unresolved - sender account not mapped]]',
      bookingLink: bookingLink || ''
    };

    const draftText = lines
      .map(line => line.replace(/<<(\\w+)>>/g, (match, key) => (
        Object.prototype.hasOwnProperty.call(substitutions, key) ? substitutions[key] : [[ + key + : unresolved]]
      )))
      .join('\n\n');

    draft = {
      template_id: templateId,
      draft_text: draftText,
      draft_status: decision.reply_draft_status || 'DRAFT_PENDING_REVIEW',
      missing_variables: missingVariables,
      human_review_required: decision.human_review_required === true,
      sender_config: {
        eaccount: eaccountKey,
        senderName,
        sender_name: senderName,
        bookingLink,
        booking_link: bookingLink
      },
      notes: template.note || null
    };
  }

  return {
    json: {
      ...input,
      draft
    }
  };
});

